// Parse Gemini output and compute deterministic risk level
const item = $input.first().json;
let raw = item.content ?? item.text ?? item.response ?? item.message ?? '';
if (typeof raw === 'object' && raw !== null) {
  raw = JSON.stringify(raw);
}

function bandFromScore(score) {
  if (score <= 40) return 'Low';
  if (score <= 70) return 'Medium';
  return 'High';
}

let parsed = null;
if (typeof raw === 'string' && raw.trim().length) {
  let cleaned = raw.trim();
  // strip markdown code fences if present
  cleaned = cleaned.replace(/^\`\`\`(json)?/i, '').replace(/\`\`\`$/,'').trim();
  const start = cleaned.indexOf('{');
  const end = cleaned.lastIndexOf('}');
  if (start !== -1 && end !== -1 && end > start) {
    cleaned = cleaned.slice(start, end + 1);
  }
  try {
    parsed = JSON.parse(cleaned);
  } catch (e) {
    parsed = null;
  }
}

if (!parsed || typeof parsed !== 'object') {
  return [{
    json: {
      error: 'could not parse AI response',
      message: 'The AI did not return valid JSON. Professional medical consultation is required.',
      raw: typeof raw === 'string' ? raw : JSON.stringify(raw),
      riskLevel: 'Unknown',
      emergency: false,
    },
  }];
}

let riskScore = Number(parsed.riskScore);
if (!isFinite(riskScore)) riskScore = 0;
riskScore = Math.max(0, Math.min(100, Math.round(riskScore)));

let confidence = Number(parsed.confidence);
if (!isFinite(confidence)) confidence = 0;
confidence = Math.max(0, Math.min(100, Math.round(confidence)));

const riskLevel = bandFromScore(riskScore);
const emergency = riskLevel === 'High';

const recommendations = Array.isArray(parsed.recommendations) ? parsed.recommendations : [];
if (!recommendations.some(r => String(r).toLowerCase().includes('professional'))) {
  recommendations.push('This is an AI screening aid, not a diagnosis. Professional medical consultation is required.');
}

return [{
  json: {
    possibleDisease: parsed.possibleDisease ?? parsed.disease ?? 'Unknown',
    confidence,
    riskScore,
    riskLevel,
    specialist: parsed.specialist ?? 'General Physician',
    symptoms: Array.isArray(parsed.symptoms) ? parsed.symptoms : [],
    recommendations,
    emergency,
    disclaimer: 'This is an AI-based screening aid and not a confirmed medical diagnosis. Please consult a licensed doctor.',
  },
}];
